server {
    listen 80;
    server_name _;

    root /usr/share/nginx/html;
    index index.html;

    location /api/ {
        proxy_pass http://backend:8000;
        proxy_http_version 1.1;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;
    }

    location /socket.io/ {
        proxy_pass http://backend:8000/socket.io/;
        proxy_http_version 1.1;
        proxy_set_header Upgrade $http_upgrade;
        proxy_set_header Connection "upgrade";
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;
    }

    location / {
        try_files $uri $uri/ /index.html;
    }
}

// importeren van ww
require('dotenv').config()

// loading the required packages from node.js and express
const express = require('express')
const http = require('http')
const helmet = require('helmet')
const cors = require('cors')
const rateLimit = require('express-rate-limit')
const app = express()
const server = http.createServer(app) // http server maken
const path = require('path')
const fs = require('fs')

const publicDir = path.join(__dirname, 'public')
const indexFile = path.join(publicDir, 'index.html')



//middleware: voor mij nog onbekend maar zal later miss duidelijk worden
// Security + CORS + request parsing middleware stack.
app.disable('x-powered-by')
app.use(helmet())
app.use(cors({
    origin: process.env.CORS_ORIGIN ? process.env.CORS_ORIGIN.split(',').map((origin) => origin.trim()) : true
}))

const apiLimiter = rateLimit({
    windowMs: 15 * 60 * 1000,
    max: Number(process.env.RATE_LIMIT_MAX || 300),
    standardHeaders: true,
    legacyHeaders: false
})

app.use(express.json())
app.use(express.urlencoded({extended: false}))
app.use(express.static(publicDir))
app.use('/api', apiLimiter)

// socket.IO setup
const initializeSocket = require('./sockets')
const io = initializeSocket(server)
app.set('io', io)

//TEST
app.get('/health', function(req, res) {
    res.send({msg: 'Pizza-website staat online'})
})

if (process.env.NODE_ENV !== 'production') {
    app.get('/test', function(req, res) {
        res.json({
            message: 'Dit is een json test',
            timeStamp: new Date()
        })
    })
}

// import routes
const about = require('./routes/about')
const echo = require('./routes/echo')
const authentication = require('./routes/authentication')
const branch = require('./routes/branch')
const orders = require('./routes/orders')
const drivers = require('./routes/drivers')
const analytics = require('./routes/analytics')

// put routes online
// Route registration: each router handles its own API endpoints.
app.use('/api/about', about)
app.use('/api/echo', echo)
app.use('/api/auth', authentication)
app.use('/api/branch', branch)
app.use('/api/orders', orders(io))
app.use('/api/drivers', drivers)
app.use('/api/analytics', analytics)

app.get('*', function(req, res, next) {
    if (req.method !== 'GET') {
        return next()
    }

    if (req.path.startsWith('/api') || req.path.startsWith('/socket.io')) {
        return next()
    }

    if (!fs.existsSync(indexFile)) {
        return next()
    }

    res.sendFile(indexFile, function(err) {
        if (err) {
            next(err)
        }
    })
})



// definieer de localhost port
const port = process.env.PORT || 8000

// put server online
server.listen(port, function() { console.log("server is running on port " + port) })

const { Pool } = require('pg')

// database configuration
// Create one shared PostgreSQL connection pool for the whole backend.
const pool = process.env.DATABASE_URL
    ? new Pool({
        connectionString: process.env.DATABASE_URL,
        ssl: process.env.PGSSLMODE === 'disable' ? false : { rejectUnauthorized: false }
    })
    : new Pool({
        user: process.env.PGUSER || 'postgres',
        host: process.env.PGHOST || 'localhost',
        database: process.env.PGDATABASE || 'pizzeria',
        password: process.env.PGPASSWORD || process.env.postgreSQLww,
        port: Number(process.env.PGPORT || 5432),
        ssl: process.env.PGSSLMODE === 'require' ? { rejectUnauthorized: false } : false
    })

//test de connectie met de database
pool.query('select now()', function(err, res) {
    if(err) {console.error("Database connection is mislukt: ", err)}
    else {console.log("Database verbonden", res.rows[0])}
})

// Listen for unexpected errors on idle clients.
pool.on('error', function(err) {
    console.error('Onverwachte database fout op idle client:', err)
})

// maakt functie global
module.exports = pool
